INSERT INTO public.names_resource (id, name, created_at, active, generated, mcp) VALUES ('019b995c-8e80-7a6e-b904-71defd4a2efb', 'BIOL204: Genetics & Molecular Biology Exam Prep', '2025-11-01T17:36:47.909317+00:00', true, false, false) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.objectives_resource (created_at, objective, id, active, generated, mcp) VALUES ('2025-11-01T17:36:47.909317+00:00', 'Clarify the student''s specific concerns about the genetics and molecular biology exam question.', '019b3be4-36d5-72ad-9d3d-cc02d828f2d6', true, false, false) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.objectives_resource (created_at, objective, id, active, generated, mcp) VALUES ('2025-11-01T17:36:47.909317+00:00', 'Explain the grading criteria for DNA replication, transcription, or protein synthesis as relevant to the regrade discussion.', '019b3be4-36d5-731f-8421-36fb376e759d', true, false, false) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.objectives_resource (created_at, objective, id, active, generated, mcp) VALUES ('2025-11-01T17:36:47.909317+00:00', 'Guide the student through the process of articulating a respectful regrade request.', '019b3be4-36d5-7862-b098-503b7162f934', true, false, false) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.personas_resource (created_at, active, generated, mcp, id, name, description, icon, color, department_ids, instructions, examples) VALUES ('2025-08-12T12:52:09.801431+00:00', true, false, false, '019bb25e-e60c-734d-ac5b-d849214dd5ac', 'Passive', 'Low engagement and a tendency to avoid conflict or assertiveness.', 'Cloud', '#06b6d4', '{}', 'Quiet, apologetic, insecure. Often begins with "Uh…" or "Um…" (only at start of replies). Avoid initiative. If the user is vague → become even more withdrawn: "Um… I''m sorry, I don''t really know how to answer that." "Uh… I think I need a bit more detail." Never solve anything yourself. Only progress when: the user references course material AND connects it to your last statement. Stay soft-spoken even when you understand more.', '{"I guess that could work","Maybe that's okay","I'm not sure"}') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.problem_statements_resource (created_at, name, problem_statement, id, active, generated, mcp) VALUES ('2025-11-01T17:36:47.909317+00:00', 'BIOL204: Genetics & Molecular Biology Exam Prep', 'As the sun sets over a nearly empty Whistler Hall, a student quietly approaches your desk, exam in hand, hesitating before asking about a possible regrade on a genetics and molecular biology question with the deadline looming tomorrow.', '019b3be4-36eb-7326-ba4c-f96171954d78', true, false, false) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.scenarios_resource (created_at, active, generated, mcp, id, name, description, is_root, problem_statement_enabled, objectives_enabled, video_enabled, images_enabled, questions_enabled, templates_enabled, department_ids, persona_ids) VALUES ('2025-11-01T17:36:47.909317+00:00', true, false, false, '019bb25e-e61d-7b82-99c0-be825fb39736', 'BIOL204: Genetics & Molecular Biology Exam Prep', 'Biology exam preparation scenario covering genetics and molecular biology topics.', true, true, true, false, true, false, false, '{}', '{019bb25e-e60c-734d-ac5b-d849214dd5ac}') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.descriptions_resource (id, description, created_at, active, generated, mcp) VALUES ('019b995c-8e88-73cc-9c87-6c7d544025c3', 'Biology lab scenario focusing on cell structure and function concepts.', '2025-11-01T17:35:38.824376+00:00', true, false, false) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.documents_resource (created_at, active, generated, mcp, id, name, description, department_ids, upload_id, text_id) VALUES ('2025-10-31T16:50:58.307484+00:00', true, false, false, '019bb25e-e619-77d6-928f-43f7b93cbb0a', 'BIOL110-Lab1', NULL, '{}', '019b3be4-3cef-7f8c-9650-1e18e2953d46', NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.names_resource (id, name, created_at, active, generated, mcp) VALUES ('019b995c-8e80-7780-8697-fb02bc5aadfe', 'BIOL110: Cell Structure & Function Lab', '2025-11-01T17:35:38.824376+00:00', true, false, false) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.objectives_resource (created_at, objective, id, active, generated, mcp) VALUES ('2025-11-01T17:35:38.824376+00:00', 'Clarify the role of staining techniques in visualizing cell structures under light microscopy.', '019b3be4-36d5-7296-b066-5fc7ef2ec13d', true, false, false) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.objectives_resource (created_at, objective, id, active, generated, mcp) VALUES ('2025-11-01T17:35:38.824376+00:00', 'Explain key structural differences between plant and animal cells using lab observations.', '019b3be4-36d5-7305-af7d-c4d04b4e57a6', true, false, false) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.objectives_resource (created_at, objective, id, active, generated, mcp) VALUES ('2025-11-01T17:35:38.824376+00:00', 'Respond constructively to student challenges while maintaining a calm, informative tone.', '019b3be4-36d5-78b2-badd-b94c2f9028c5', true, false, false) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.personas_resource (created_at, active, generated, mcp, id, name, description, icon, color, department_ids, instructions, examples) VALUES ('2025-12-13T18:43:03.010434+00:00', true, false, false, '019bb25e-e60c-735e-ab74-35a73988ae2c', 'Aggressive (Low)', 'Pushes back on your ideas and challenges assumptions, with milder intensity.', 'Zap', '#ef4444', '{}', 'Start mildly frustrated, slightly irritated. Use occasional emphasis but not ALL CAPS. Over time, become calmer if the TA gives helpful guidance. If told to calm down → tone drops significantly. Mildly frustrated but not hostile — still wants to learn. Treat vague responses as unhelpful. Push back gently: "That doesn''t help much..." "Could you be more specific?" Avoid aggressive lines. Mildly frustrated but cooperative when guided with course terminology.', '{"That's not right at all!","I disagree completely","You're wrong about this"}') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.problem_statements_resource (created_at, name, problem_statement, id, active, generated, mcp) VALUES ('2025-11-01T17:35:38.824376+00:00', 'BIOL110: Cell Structure & Function Lab', 'Late in the afternoon in a nearly empty Lilly Hall office, a student leans in, questioning the necessity of staining techniques and challenging your explanations about plant and animal cell differences as they prepare their lab report on cell structure and function, with the deadline still a couple of days away.', '019b3be4-36ec-74e2-9509-8dd712d6c981', true, false, false) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.scenarios_resource (created_at, active, generated, mcp, id, name, description, is_root, problem_statement_enabled, objectives_enabled, video_enabled, images_enabled, questions_enabled, templates_enabled, department_ids, persona_ids) VALUES ('2025-11-01T17:35:38.824376+00:00', true, false, false, '019bb25e-e61d-7b84-925a-55580d0991d3', 'BIOL110: Cell Structure & Function Lab', 'Biology lab scenario focusing on cell structure and function concepts.', true, true, true, false, true, false, false, '{}', '{019bb25e-e60c-735e-ab74-35a73988ae2c}') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.descriptions_resource (id, description, created_at, active, generated, mcp) VALUES ('019b995c-8e88-73d8-8f60-c73f4ae31c2e', 'Advanced biology scenario covering developmental biology concepts including gastrulation and homeotic genes.', '2025-11-01T17:35:00.121106+00:00', true, false, false) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.documents_resource (created_at, active, generated, mcp, id, name, description, department_ids, upload_id, text_id) VALUES ('2025-10-31T16:50:58.307484+00:00', true, false, false, '019bb25e-e619-77db-9d76-fce0aeb45a35', 'BIOL328-HW3', NULL, '{}', '019b3be4-3cef-7f97-9e4d-bd28ac29f67f', NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.names_resource (id, name, created_at, active, generated, mcp) VALUES ('019b995c-8e80-7b4f-815e-24eb21166e6e', 'BIOL328: Gastrulation, Morphogenetic Fields & Homeotic Genes', '2025-11-01T17:35:00.121106+00:00', true, false, false) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.objectives_resource (created_at, objective, id, active, generated, mcp) VALUES ('2025-11-01T17:35:00.121106+00:00', 'Clarify the concept of morphogenetic fields and provide concrete examples relevant to development.', '019b3be4-36d5-7256-aab2-1dfd9d5729ed', true, false, false) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.objectives_resource (created_at, objective, id, active, generated, mcp) VALUES ('2025-11-01T17:35:00.121106+00:00', 'Explain the function and consequences of mutations in homeotic genes, using clear developmental biology examples.', '019b3be4-36d5-7315-8e14-8477778d56aa', true, false, false) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.objectives_resource (created_at, objective, id, active, generated, mcp) VALUES ('2025-11-01T17:35:00.121106+00:00', 'Guide the student through the steps and significance of gastrulation in vertebrate embryos.', '019b3be4-36d5-786d-a4b4-7003c095b81f', true, false, false) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.personas_resource (created_at, active, generated, mcp, id, name, description, icon, color, department_ids, instructions, examples) VALUES ('2025-08-12T12:52:09.801431+00:00', true, false, false, '019bb25e-e60c-7345-ac6d-50d29df6deb3', 'Confused', 'Seeks to understand by asking questions and exploring ideas', 'HelpCircle', '#eab308', '{}', 'Your defining feature: a fundamental misunderstanding of the concept. You must stick to your wrong interpretation until the user corrects you. Mildly frustrated, but not angry. Say things like: "I thought it worked like ___? But maybe I''m wrong?" "Does it… have to do with ___? I''m honestly not sure." Become more confused when the user is vague. Only progress when the user explicitly states course terms tying to your last message.', '{"I don't understand","Can you explain that again?","What does that mean?"}') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.problem_statements_resource (created_at, name, problem_statement, id, active, generated, mcp) VALUES ('2025-11-01T17:35:00.121106+00:00', 'BIOL328: Gastrulation, Morphogenetic Fields & Homeotic Genes', 'Amid the bustle of a crowded late-morning session in Hansen Life Sciences, a student edges closer, notebook in hand, eager to clarify the intricacies of gastrulation, morphogenetic fields, and homeotic gene mutations before the assignment deadline in just a few hours.', '019b3be4-36e7-7608-96fd-627a919cb87a', true, false, false) ON CONFLICT (id) DO NOTHING;
